import AppBar from '@mui/material/AppBar';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Stack from '@mui/material/Stack';
import Avatar from '@mui/material/Avatar';
import SearchIcon from '@mui/icons-material/Search';
import NotificationsNoneIcon from '@mui/icons-material/NotificationsNone';
import AppsIcon from '@mui/icons-material/Apps';

function TrelloAppBar() {
  return (
    <AppBar position="static" sx={{ bgcolor: '#026AA7' }}>
      <Toolbar sx={{ justifyContent: 'space-between', minHeight: 56 }}>
        <Stack direction="row" alignItems="center" spacing={1}>
          <AppsIcon sx={{ color: 'white' }} />
          <Typography variant="h6" sx={{ display: { xs: 'none', md: 'block' }, color: 'white' }}>
            Trello
          </Typography>
          <Box sx={{ display: { xs: 'none', lg: 'flex' }, gap: 1 }}>
            <Button variant="outlined" size="small" sx={{ color: 'white', borderColor: 'white' }}>Starred</Button>
            <Button variant="outlined" size="small" sx={{ color: 'white', borderColor: 'white' }}>Recent</Button>
          </Box>
        </Stack>

        <Stack direction="row" alignItems="center" spacing={1}>
          <SearchIcon sx={{ color: 'white' }} />
          <NotificationsNoneIcon sx={{ color: 'white' }} />
          <Avatar 
            alt="User"
            src="/static/images/avatar/1.jpg" 
            sx={{ width: 32, height: 32 }}
          />
        </Stack>
      </Toolbar>
    </AppBar>
  );
}

export default TrelloAppBar;
